from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer
import time
from functools import wraps
from collections import defaultdict
import hashlib
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# In-memory storage for users and rate limiting
users_db = {}
rate_limit = defaultdict(list)
MAX_ATTEMPTS = 5
TIME_WINDOW = 300  # 5 minutes

# Token serializer for secure token generation
serializer = Serializer(app.config['SECRET_KEY'], expires_in=3600)  # 1 hour expiry

def rate_limit_decorator(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        client_ip = request.remote_addr
        current_time = time.time()
        
        # Clean old attempts
        rate_limit[client_ip] = [t for t in rate_limit[client_ip] if current_time - t < TIME_WINDOW]
        
        if len(rate_limit[client_ip]) >= MAX_ATTEMPTS:
            return jsonify({'error': 'Too many attempts. Please try again later.'}), 429
        
        result = func(*args, **kwargs)
        if request.method == 'POST' and '/login' in request.path:
            if result.status_code != 200:
                rate_limit[client_ip].append(current_time)
        return result
    return wrapper

def generate_token(user_id):
    return serializer.dumps({'user_id': user_id}).decode('utf-8')

def verify_token(token):
    try:
        data = serializer.loads(token)
        return data['user_id']
    except:
        return None

def hash_password(password):
    return generate_password_hash(password, method='pbkdf2:sha256')

def verify_password(stored_password, provided_password):
    return check_password_hash(stored_password, provided_password)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        user_id = verify_token(token)
        if not user_id:
            return jsonify({'error': 'Token is invalid or expired'}), 401
        
        return f(user_id, *args, **kwargs)
    return decorated

@app.route('/register', methods=['POST'])
@rate_limit_decorator
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409
    
    users_db[username] = hash_password(password)
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/login', methods=['POST'])
@rate_limit_decorator
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if not verify_password(users_db[username], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    token = generate_token(username)
    return jsonify({'token': token}), 200

